class Vehicle {
  int getSpeed() => 50;
}

class Jet extends Vehicle {
  // Override the inherited logic entirely!
  @override
  int getSpeed() => 500;
}

void main() {
  Vehicle v = Vehicle();
  Jet j = Jet();

  print(v.getSpeed()); // 50
  print(j.getSpeed()); // 500
}
